INSERT INTO `notice` VALUES (1, 'þ│╗þ╗ƒþ╗┤µèñÚÇÜþƒÑ´╝êµ¡úÕ╝Åþëê´╝ë', '<p style=\"text-align: start;\"><strong>­ƒôó Õà│õ║Äþ│╗þ╗ƒÕìçþ║ºþ╗┤µèñþÜäÕà¼ÕæèÔÇï</strong>ÔÇï<br>Õ░èµò¼þÜäÕÉäõ¢ìþö¿µêÀ´╝Ü<br>õ©║µÅÉõ¥øµø┤õ╝ÿÞ┤¿þÜäµ£ìÕèí´╝îÕ╣│ÕÅ░Õ░åõ║Ä ÔÇï<strong>ÔÇï2025Õ╣┤7µ£ê15µùÑ 00:00Þç│06:00ÔÇï</strong>ÔÇï Þ┐øÞíîþ│╗þ╗ƒÕìçþ║ºþ╗┤µèñÒÇéµ£ƒÚù┤ÕÅ»Þâ¢Õç║þÄ░þƒ¡µÜéµùáµ│òÞ«┐Úù«þÜäµâàÕåÁ´╝îÕ╗║Þ««µé¿µÅÉÕëìõ┐ØÕ¡ÿµò░µì«ÒÇé<br>­ƒö╣ Õ¢▒ÕôìÞîâÕø┤´╝ÜÕà¿Úâ¿ÕèƒÞâ¢µ¿íÕØù<br>­ƒö╣ ÞíÑÕü┐µû╣µíê´╝Üþ╗┤µèñþ╗ôµØƒÕÉÄµëÇµ£ëþö¿µêÀÕ░åÞÄÀÕ¥ù ÔÇï<strong>ÔÇï50þº»ÕêåÔÇï</strong>ÔÇï ÞíÑÕü┐<br>µäƒÞ░óµé¿þÜäþÉåÞºúõ©Äµö»µîü´╝üÕªéµ£ëþ┤ºµÇÑÚù«Úóÿ´╝îÞ»ÀÞüöþ│╗Õ«óµ£ìÚé«þ«▒´╝Üsupport@example.com</p><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïÔÇ£µÖ║µàºµë¥µê┐ÔÇØÕ╣│ÕÅ░Þ┐ÉÞÉÑÕøóÚÿƒÔÇï</strong>ÔÇï<br>2025Õ╣┤7µ£ê14µùÑ</p>', '2025-07-14 17:29:57');
INSERT INTO `notice` VALUES (2, 'µû░ÕèƒÞâ¢õ©èþ║┐´╝êµ┤╗µ│╝þëê´╝ëÔÇï', '<p style=\"text-align: start;\"><strong>­ƒÄë Úçìþúàµø┤µû░´╝üÒÇîµÖ║Þâ¢Õè®µëï2.0ÒÇìõ©èþ║┐Õòª´╝üÔÇï</strong>ÔÇï<br>õ║▓þê▒þÜäþö¿µêÀµ£ïÕÅïõ╗¼´╝Ü<br>õ¢áõ╗¼µ£ƒÕ¥àþÜä ÔÇï<strong>ÔÇïAIµÖ║Þâ¢Õè®µëïÔÇï</strong>ÔÇï Õà¿µû░Õìçþ║º´╝üþÄ░Õ£¿µö»µîü´╝Ü<br>Ô£à ÕñÜÞ»¡Þ¿ÇÕ«×µùÂþ┐╗Þ»æ<br>Ô£à µûçµíúµÖ║Þâ¢þ║áÚöÖ<br>Ô£à õ©ÇÚö«þöƒµêÉµÇØþ╗┤Õ»╝Õø¥<br>ÔÇï<strong>ÔÇï­ƒæë þ½ïÕì│õ¢ôÚ¬îÔÇï</strong>ÔÇï´╝Ü[þé╣Õç╗Þ┐ÖÚçîÞÀ│Þ¢¼µû░ÕèƒÞâ¢ÚíÁ]</p><p style=\"text-align: start;\">Ô£¿ ÔÇï<strong>ÔÇïÚÖÉµùÂþªÅÕê®ÔÇï</strong>ÔÇï´╝Ü7µ£ê14µùÑ-7µ£ê20µùÑõ¢┐þö¿µû░ÕèƒÞâ¢ÕÅ»ÕÅéõ©Äµè¢ÕÑû´╝îÞÁóÕÅûµ£║µó░Úö«þøÿ´╝ü</p><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïµèÇµ£»Õ░ÅÕôÑÞ┐×Õñ£þºâÕñ┤Õç║Õôü´╝îµ▒éÕÑ¢Þ»ä´╝üÔÇï</strong>ÔÇï<br>ÔÇöÔÇöõ║ºÕôüÕ░ÅÕêåÚÿƒ</p><p style=\"text-align: start;\"><strong>­ƒÄë Úçìþúàµø┤µû░´╝üÒÇîµÖ║Þâ¢Õè®µëï2.0ÒÇìõ©èþ║┐Õòª´╝üÔÇï</strong>ÔÇï<br>õ║▓þê▒þÜäþö¿µêÀµ£ïÕÅïõ╗¼´╝Ü<br>õ¢áõ╗¼µ£ƒÕ¥àþÜä ÔÇï<strong>ÔÇïAIµÖ║Þâ¢Õè®µëïÔÇï</strong>ÔÇï Õà¿µû░Õìçþ║º´╝üþÄ░Õ£¿µö»µîü´╝Ü<br>Ô£à ÕñÜÞ»¡Þ¿ÇÕ«×µùÂþ┐╗Þ»æ<br>Ô£à µûçµíúµÖ║Þâ¢þ║áÚöÖ<br>Ô£à õ©ÇÚö«þöƒµêÉµÇØþ╗┤Õ»╝Õø¥<br>ÔÇï<strong>ÔÇï­ƒæë þ½ïÕì│õ¢ôÚ¬îÔÇï</strong>ÔÇï´╝Ü[þé╣Õç╗Þ┐ÖÚçîÞÀ│Þ¢¼µû░ÕèƒÞâ¢ÚíÁ]</p><p style=\"text-align: start;\">Ô£¿ ÔÇï<strong>ÔÇïÚÖÉµùÂþªÅÕê®ÔÇï</strong>ÔÇï´╝Ü7µ£ê14µùÑ-7µ£ê20µùÑõ¢┐þö¿µû░ÕèƒÞâ¢ÕÅ»ÕÅéõ©Äµè¢ÕÑû´╝îÞÁóÕÅûµ£║µó░Úö«þøÿ´╝ü</p><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïµèÇµ£»Õ░ÅÕôÑÞ┐×Õñ£þºâÕñ┤Õç║Õôü´╝îµ▒éÕÑ¢Þ»ä´╝üÔÇï</strong>ÔÇï<br>ÔÇöÔÇöõ║ºÕôüÕ░ÅÕêåÚÿƒ</p><p style=\"text-align: start;\"><strong>­ƒÄë Úçìþúàµø┤µû░´╝üÒÇîµÖ║Þâ¢Õè®µëï2.0ÒÇìõ©èþ║┐Õòª´╝üÔÇï</strong>ÔÇï<br>õ║▓þê▒þÜäþö¿µêÀµ£ïÕÅïõ╗¼´╝Ü<br>õ¢áõ╗¼µ£ƒÕ¥àþÜä ÔÇï<strong>ÔÇïAIµÖ║Þâ¢Õè®µëïÔÇï</strong>ÔÇï Õà¿µû░Õìçþ║º´╝üþÄ░Õ£¿µö»µîü´╝Ü<br>Ô£à ÕñÜÞ»¡Þ¿ÇÕ«×µùÂþ┐╗Þ»æ<br>Ô£à µûçµíúµÖ║Þâ¢þ║áÚöÖ<br>Ô£à õ©ÇÚö«þöƒµêÉµÇØþ╗┤Õ»╝Õø¥<br>ÔÇï<strong>ÔÇï­ƒæë þ½ïÕì│õ¢ôÚ¬îÔÇï</strong>ÔÇï´╝Ü[þé╣Õç╗Þ┐ÖÚçîÞÀ│Þ¢¼µû░ÕèƒÞâ¢ÚíÁ]</p><p style=\"text-align: start;\">Ô£¿ ÔÇï<strong>ÔÇïÚÖÉµùÂþªÅÕê®ÔÇï</strong>ÔÇï´╝Ü7µ£ê14µùÑ-7µ£ê20µùÑõ¢┐þö¿µû░ÕèƒÞâ¢ÕÅ»ÕÅéõ©Äµè¢ÕÑû´╝îÞÁóÕÅûµ£║µó░Úö«þøÿ´╝ü</p><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïµèÇµ£»Õ░ÅÕôÑÞ┐×Õñ£þºâÕñ┤Õç║Õôü´╝îµ▒éÕÑ¢Þ»ä´╝üÔÇï</strong>ÔÇï<br>ÔÇöÔÇöõ║ºÕôüÕ░ÅÕêåÚÿƒ</p>', '2025-07-14 17:30:45');
INSERT INTO `notice` VALUES (3, 'Þ┐ØÞºäµò┤µ▓╗Õà¼Õæè´╝êõ©ÑÞéâþëê´╝ëÔÇï', '<p style=\"text-align: start;\"><strong>ÔÜá´©Å Õà│õ║Äõ©ÑÕÄëµëôÕç╗Þ┐ØÞºäÕåàÕ«╣þÜäÕà¼ÕæèÔÇï</strong>ÔÇï<br>Þ┐æµ£ƒÕÅæþÄ░Úâ¿Õêåþö¿µêÀÕ¡ÿÕ£¿ ÔÇï<strong>ÔÇïµüÂµäÅþüîµ░┤ÒÇüÕÅæÕ©âÕ╣┐ÕæèÔÇï</strong>ÔÇï þ¡ëÞíîõ©║´╝îÕ╣│ÕÅ░Õ░åÚççÕÅûõ╗Ñõ©ïµÄ¬µû¢´╝Ü</p><ol><li style=\"text-align: left;\">Õì│µùÑÞÁÀÕÉ»þö¿AIÕåàÕ«╣Õ«íµá©þ│╗þ╗ƒ</li><li style=\"text-align: left;\">þ┤»Þ«í3µ¼íÞ┐ØÞºäÕ░åµ░©õ╣àÕ░üÕÅÀ</li><li style=\"text-align: left;\">Õ╝ÇÚÇÜõ©¥µèÑÕÑûÕè▒ÚÇÜÚüô´╝êµá©Õ«×ÕÉÄÕÑûÕè▒5-100þº»Õêå´╝ë</li></ol><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïÕçÇÕîûþñ¥Õî║þÄ»Õóâ´╝îÚ£ÇÞªüõ¢áµêæÕà▒ÕÉîÕÅéõ©Ä´╝üÔÇï</strong>ÔÇï<br>õ©¥µèÑÕàÑÕÅú´╝Üõ©¬õ║║õ©¡Õ┐â-ÒÇîµäÅÞºüÕÅìÚªêÒÇì</p><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïXXÕ╣│ÕÅ░þ«íþÉåÕºöÕæÿõ╝ÜÔÇï</strong>ÔÇï<br>2025Õ╣┤7µ£ê14µùÑ</p><p style=\"text-align: start;\"><strong>ÔÜá´©Å Õà│õ║Äõ©ÑÕÄëµëôÕç╗Þ┐ØÞºäÕåàÕ«╣þÜäÕà¼ÕæèÔÇï</strong>ÔÇï<br>Þ┐æµ£ƒÕÅæþÄ░Úâ¿Õêåþö¿µêÀÕ¡ÿÕ£¿ ÔÇï<strong>ÔÇïµüÂµäÅþüîµ░┤ÒÇüÕÅæÕ©âÕ╣┐ÕæèÔÇï</strong>ÔÇï þ¡ëÞíîõ©║´╝îÕ╣│ÕÅ░Õ░åÚççÕÅûõ╗Ñõ©ïµÄ¬µû¢´╝Ü</p><ol><li style=\"text-align: left;\">Õì│µùÑÞÁÀÕÉ»þö¿AIÕåàÕ«╣Õ«íµá©þ│╗þ╗ƒ</li><li style=\"text-align: left;\">þ┤»Þ«í3µ¼íÞ┐ØÞºäÕ░åµ░©õ╣àÕ░üÕÅÀ</li><li style=\"text-align: left;\">Õ╝ÇÚÇÜõ©¥µèÑÕÑûÕè▒ÚÇÜÚüô´╝êµá©Õ«×ÕÉÄÕÑûÕè▒5-100þº»Õêå´╝ë</li></ol><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïÕçÇÕîûþñ¥Õî║þÄ»Õóâ´╝îÚ£ÇÞªüõ¢áµêæÕà▒ÕÉîÕÅéõ©Ä´╝üÔÇï</strong>ÔÇï<br>õ©¥µèÑÕàÑÕÅú´╝Üõ©¬õ║║õ©¡Õ┐â-ÒÇîµäÅÞºüÕÅìÚªêÒÇì</p><p style=\"text-align: start;\">ÔÇï<strong>ÔÇïXXÕ╣│ÕÅ░þ«íþÉåÕºöÕæÿõ╝ÜÔÇï</strong>ÔÇï<br>2025Õ╣┤7µ£ê14µùÑ</p>', '2025-07-14 17:31:17');
